class Solution:
    def maximizeSum(self, nums, k):
        v = max(nums)
        total = 0
        for _ in range(k):
            total += v
            v += 1
        return total

solutions.python:
class Solution:
    def maximizeSum(self, nums, k):
        m = max(nums)
        return k * m + k * (k - 1) // 2

